<template>
    <div class="product-filter-tab-container">
        <div class="product-filter-title" v-if="title">
            <span>{{title}}</span>
        </div>
        <ul class="nav filter-button-container">
            <li class="nav-item" v-for="(item , index) in tab" :key="`tab_${index}`" >
                <span @click="changeTab(item)" class="btn btn-radius-border" :class="{ 'active' : value == item.name }">
                    <template v-if="item.icon && item.icon != ''">
                        <span v-html="item.icon"></span>
                    </template>
                    {{item.name}}
                </span>
            </li>
        </ul>
    </div>
</template>

<script>
    export default {
        name: "product-filter-tab",
        props:{
            title : {
                type : String,
            },
            tab : {
                type : Array,
            },
            value : {
                type : String
            },
        },
        methods: {
            changeTab: function (tab) {
                if( this.active != tab ){
                    this.$emit('input' , tab.name)
                    this.$emit('on-change-tab',tab)
                }
            }
        }
    }
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';
    html.touch *:hover {
        pointer-events: none !important;
    }
    .product-filter-tab-container {
        margin-bottom: 30px;
        width: 100%;
        display: flex;
        .filter-button-container {
            flex: 1;
            text-align: right;
            display: block;
            .nav-item {
                display: inline-block;
                &:focus {
                    outline: none;
                }
            }
            span , a{
                color: $black;
                text-transform: capitalize;
                &:hover {
                    cursor: pointer;
                }
                &.active {
                    border: 1px solid $yellow;
                }
            }
        }
    }
</style>
